const incoming = $input.first().json;
const existing = $('Fetch Guest Profiles').first().json;

const existingAllergies = existing.food_allergies || [];
const newAllergies = incoming.food_allergies || [];
const mergedAllergies = [...new Set([...existingAllergies, ...newAllergies])];

const updatedProfile = {
  guest_key: incoming.guest_key,
  guest_id: incoming.guest_id || existing.guest_id,
  name: incoming.name || existing.name,
  email: incoming.email || existing.email,
  phone: incoming.phone || existing.phone,
  room_preference: incoming.room_preference || existing.room_preference,
  food_allergies: mergedAllergies,
  special_occasion: incoming.special_occasion || existing.special_occasion,
  check_in_date: incoming.check_in_date,
  visit_count: (existing.visit_count || 0) + 1,
  last_visit_date: new Date().toISOString(),
  profile_id: existing.id
};

return { json: updatedProfile };

const incoming = $input.first().json;

const newProfile = {
  guest_key: incoming.guest_key,
  guest_id: incoming.guest_id,
  name: incoming.name,
  email: incoming.email,
  phone: incoming.phone,
  room_preference: incoming.room_preference,
  food_allergies: incoming.food_allergies || [],
  special_occasion: incoming.special_occasion,
  check_in_date: incoming.check_in_date,
  visit_count: 1,
  last_visit_date: new Date().toISOString(),
  created_at: new Date().toISOString()
};

return { json: newProfile };

const checkInDate = new Date($json.check_in_date);
const now = new Date();
const diffTime = checkInDate - now;
const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

return {
  json: {
    ...($json),
    days_until_checkin: diffDays,
    within_window: diffDays <= 2 && diffDays >= 0
  }
};
